"""
mkt-context layer — 2 Corinthians chapters 1–5
Output: data/commentary/mkt-context/2corinthians.json
Run: python3 scripts/zc-context-2corinthians-1-5.py
"""
import json, pathlib

ROOT = pathlib.Path(__file__).parent.parent

def load_comm(source, book):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    if p.exists():
        return json.loads(p.read_text())
    return {}

def save_comm(source, book, data):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f'  wrote {p.relative_to(ROOT)}')

def merge_comm(existing, new_data):
    # INTENT: Merge new verse entries without overwriting already-present keys — safe to re-run.
    # CHANGE? If commentary JSON structure changes from {ch:{v:html}}, update this traversal.
    # VERIFY: Re-running the script should produce identical output.
    for ch, verses in new_data.items():
        if ch not in existing:
            existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = html

NEW = {
  "1": {
    "1": "Paul, an apostle of Christ Jesus by the will of God — the letter is addressed from Macedonia after Paul's painful visit to Corinth and his sending of a tearful letter via Titus (mentioned in 2:13; 7:5-16). The co-sender Timothy was well known to the Corinthians (1 Cor 4:17; 16:10). The letter's province of Achaia includes both Corinth and the surrounding region.",
    "2": "Grace to you and peace from God our Father and the Lord Jesus Christ — the standard Pauline salutation combining the Greek greeting (charis/grace) with the Jewish greeting (shalom/eirēnē/peace). The dual source (Father and Son) reflects Paul's binitarian way of speaking about God from the earliest letters.",
    "3": "Blessed be the God and Father of our Lord Jesus Christ, the Father of mercies and God of all comfort — the berakah (blessing) form comes from Jewish liturgical prayer; synagogue services and the Jewish prayer book (siddur) regularly opened petitions with blessed are you, O Lord. Paul converts the personal berakah into apostolic proclamation.",
    "4": "Who comforts us in all our affliction (thlipsis) — the word group parakaleo/paraklesis (comfort, encourage, exhort) appears ten times in vv.3-7, an unprecedented density in any Pauline passage. Thlipsis (affliction, pressure, tribulation) was Paul's standard term for the sufferings that attended apostolic ministry in the Greco-Roman world.",
    "5": "For as we share abundantly in Christ's sufferings, so through Christ we share abundantly in comfort too — the participatory language reflects Paul's theology of union with Christ: the apostle's sufferings are a participation (koinonia) in Christ's own pathēmata (sufferings). This is not masochism but mission theology.",
    "6": "If we are afflicted, it is for your comfort and salvation — the directional movement of suffering: Paul's pain becomes the Corinthians' benefit. This reflects the ancient Mediterranean concept of the benefactor who undergoes hardship for the good of the community, but Paul's ground is christological.",
    "7": "Our hope for you is unshaken, for we know that as you share in our sufferings, you will also share in our comfort — the partnership (koinonia) of suffering and comfort between apostle and congregation mirrors the early Christian community's actual experience of mutual support during persecution (Acts 2:44-45; 4:32-35).",
    "9": "Indeed, we felt that we had received the sentence of death — the katakrimia (verdict of death, death-sentence) is hyperbolic but reflects a real life-threatening experience in the province of Asia. So that we would rely not on ourselves but on God who raises the dead — the resurrection is Paul's practical resource for enduring mortal danger, not merely a theological belief.",
    "10": "He delivered us from such a deadly peril, and he will deliver us — the triple tenses (past: delivered; present: delivers; future: will deliver) mirror the Jewish thanksgiving prayer form (hodayah) that reflects on past deliverance as the basis for present trust and future hope.",
    "11": "You also must help us by prayer, so that many will give thanks on our behalf for the blessing granted us through the prayers of many — the communal prayer network as the practical mechanism of apostolic support. In the ancient Mediterranean world, prayer requests were sent through letter-networks; Paul's letters frequently ask for and report on prayer.",
    "12": "For our boast is this, the testimony of our conscience — syneidesis (conscience) was a Stoic philosophical concept for the internal moral judge. Paul's appeal to conscience as the basis of his conduct reflects his adoption of Hellenistic moral vocabulary to describe the apostolic life of transparent integrity.",
    "13": "For we are not writing to you anything other than what you read and understand — the assertion of plain writing is significant in a context where ancient letters were sometimes deliberately opaque to outsiders. Paul insists his meaning is accessible rather than coded.",
    "14": "Just as you have understood in part, that on the day of our Lord Jesus you will boast of us as we will boast of you — the eschatological day (hēmera tou kyriou) provides the ultimate frame of reference for all present evaluations. What matters is not Corinthian opinion of Paul today but the mutual acknowledgment on the day of Christ.",
    "15": "Because I was sure of this, I wanted to come to you first, so that you might have a double pleasure (charin, grace/benefit) — Paul's original travel plan had been to visit Corinth twice (on the way to Macedonia and on the return). The change of plan became the occasion for accusations of fickleness.",
    "16": "I wanted to visit you on my way to Macedonia and to come back to you from Macedonia and have you send me on my way to Judea — the Corinthian-Macedonia-Judea triangle was the route of the Jerusalem collection; Corinth's role in the collection was significant (1 Cor 16:1-4; 2 Cor 8-9).",
    "17": "Was I vacillating when I wanted to do this? Do I make my plans according to the flesh (kata sarka)? — the accusation Paul is defending against: that his change of travel plans reflects the unreliability of a person who acts on worldly impulse rather than Spirit-guided apostolic consistency.",
    "18": "As surely as God is faithful, our word to you has not been Yes and No — the divine faithfulness (pistos ho theos) is the warrant for Paul's own consistency. The Corinthian accusation of yes-and-no inconsistency is refuted by appeal to the character of the God Paul serves.",
    "19": "For the Son of God, Jesus Christ, whom we proclaimed among you, Silvanus and Timothy and I, was not Yes and No, but in him it is always Yes — the consistency of the gospel message (Jesus Christ the same yesterday, today, and forever — Heb 13:8) grounds the consistency of the apostolic messenger.",
    "20": "For all the promises of God find their Yes in him — the christological fulfillment of OT promise. That is why it is through him that we utter our Amen to God for his glory — the amen as liturgical response: in Jewish synagogue practice, the congregation's amen ratified the leader's prayer (Neh 8:6; 1 Chr 16:36). The Christian practice inherits this.",
    "21": "It is God who establishes us with you in Christ, and has anointed us — the verb chriō (anoint) shares its root with Christos (Anointed One/Christ). Paul applies the anointing language to all believers: as Christ is the Anointed One, so believers are anointed ones. This priestly and prophetic anointing was associated with the Spirit in OT (1 Sam 10:1; Isa 61:1).",
    "22": "And who has also put his seal (sphragisas) on us and given us his Spirit in our hearts as a guarantee (arrabōn) — arrabōn was a commercial term for a deposit or down-payment that guaranteed the full payment to follow. The word appears in Greek papyri for earnest money in property transactions. The Spirit is God's arrabōn guaranteeing the full inheritance (Eph 1:14).",
    "23": "But I call God to witness against me — the solemn oath before the divine witness reflects both Greco-Roman legal practice (calling deities as witnesses to oaths) and Jewish oath-taking conventions (Jer 42:5: the Lord be a true and faithful witness against us). It was to spare you that I refrained from coming to Corinth.",
    "24": "Not that we lord it over (kyrieuo) your faith, but we work with you for your joy — the political metaphor: kyrieuo was the verb for exercising lordship, the authority of the kyrios (lord). Roman provincial governors exercised this kind of authority over their provinces. Paul explicitly renounces this model of apostolic authority.",
  },
  "2": {
    "1": "I made up my mind not to make another painful visit to you — the painful visit (en lypē) refers to Paul's second visit to Corinth (the first was the founding visit of Acts 18:1-18). This second visit is mentioned in 2 Cor 13:2 and was apparently marked by conflict with a particular person (2:5-11).",
    "2": "For if I cause you pain, who is there to make me glad but the one whom I have pained? — the pastoral logic: the apostle's joy is bound up with the congregation's joy. This reflects the symbiotic relationship between teacher and community in ancient Mediterranean culture.",
    "3": "And I wrote as I did, so that when I come I might not suffer pain from those who should have made me rejoice — the tearful letter (v.4) is not 1 Corinthians but a now-lost intermediate letter, probably written after the painful visit and before 2 Corinthians. Its severe tone produced a period of estrangement.",
    "4": "For I wrote to you out of much affliction and anguish of heart and with many tears, not to cause you pain but to let you know the abundant love that I have for you — the emotional register of this description (thlipsis, synocha kardias, dakryon pollon — affliction, anguish of heart, many tears) is unparalleled in Paul's letters.",
    "5": "Now if anyone has caused pain, he has caused it not to me, but in some measure — not to put it too severely — to all of you — the offender (ho adikēsas in v.10) is usually identified with the person who led opposition to Paul during the painful visit. The indefinite reference (tis — someone) may be diplomatic or may reflect that the identity was well known to the Corinthians.",
    "6": "For such a one, this punishment by the majority is enough — the community discipline (epitimia, censure, punishment) exercised by to pleion (the majority) suggests a formal congregational action, possibly expulsion or shaming, that Paul now says is sufficient.",
    "7": "So you should rather turn to forgive and comfort him, or he may be overwhelmed by excessive sorrow — the pastoral concern for the over-punished offender mirrors the later rabbinic principle that punishment must not reduce a person to shame beyond recovery.",
    "8": "So I beg you to reaffirm your love for him — the verb kyroō (ratify, confirm) is a legal term used for validating a decision or contract. Paul calls for an official communal act of love-reaffirmation to counterbalance the official censure.",
    "9": "For this is why I wrote, that I might test (eis to gnōnai, to know; dokimēn, proof through testing) you and know whether you are obedient in everything — the tearful letter was partly a test of whether the congregation would submit to apostolic authority. The test has been passed (7:14-16).",
    "10": "Anyone whom you forgive, I also forgive — the apostolic forgiveness pronounced by Paul mirrors the authority Jesus granted to his disciples (John 20:23: if you forgive the sins of anyone, they are forgiven). What I have forgiven, if I have forgiven anything, has been for your sake in the presence of Christ.",
    "11": "So that we would not be outwitted by Satan — the strategic awareness of satanic schemes (noēmata, designs, intentions) reflects the early Christian understanding that community divisions served demonic purposes. Paul's concern for reconciliation is therefore spiritual warfare.",
    "12": "When I came to Troas to preach the gospel of Christ, even though a door was opened for me in the Lord — the open-door metaphor for missionary opportunity (1 Cor 16:9; Col 4:3). Troas (Alexandria Troas) was an important port city on the northwest coast of Asia Minor, a major transit point between Macedonia and Asia.",
    "13": "My spirit was not at rest because I did not find my brother Titus there — Titus is Paul's trusted emissary to Corinth, mentioned only in 2 Corinthians and the Pastoral Epistles in the Pauline corpus. Paul's anxiety about Titus reflects the intense pastoral investment in the Corinthian situation.",
    "14": "But thanks be to God, who in Christ always leads us in triumphal procession (thriambeuonti) — the Roman triumph (triumphus) was the ceremonial procession granted to a general who had won a major victory. The triumphator rode in a chariot through Rome with his captives, his troops, spoils, and incense-burning priests. Paul uses this imperial spectacle to describe apostolic mission.",
    "15": "For we are the aroma of Christ to God among those who are being saved and among those who are perishing — in the Roman triumph, incense was burned throughout the procession. To the victorious Romans, the fragrance signified celebration and life; to the captives being led to execution, the same fragrance signaled death. Paul applies the dual symbolism to the gospel.",
    "16": "To one a fragrance from death to death, to the other a fragrance from life to life — the same message produces diametrically opposite effects depending on the hearer's orientation. Who is sufficient (hikanos) for these things? — the rhetorical question sets up chapter 3's answer: our sufficiency is from God (3:5).",
    "17": "For we are not, like so many, peddlers (kapeleuontes, hucksters, adulterators) of God's word — the kapēlos was a small trader often associated with adulteration of goods for profit. The contrast is with the sincere (eilikrineia) and God-commissioned messenger. The accusation of kapēleia (peddling) was a standard charge against Sophists who charged fees for their teaching.",
  },
  "3": {
    "2": "You yourselves are our letter of recommendation — in the Hellenistic world, letters of recommendation (epistolai systatikal) were essential for mobile teachers, traders, and officials who needed to establish credentials in new communities. 3 John 9-10 and Acts 18:27 both reference the practice. Paul inverts the convention: the community is the letter.",
    "3": "And you show that you are a letter from Christ delivered by us, written not with ink but with the Spirit of the living God, not on tablets of stone but on tablets of human hearts — the contrast between stone tablets and human hearts echoes Jeremiah 31:33 (the new covenant written on the heart) and Ezekiel 36:26 (a heart of flesh instead of a heart of stone). The inscribed-heart is the eschatological mark of the new covenant.",
    "4": "Such is the confidence (pepoithēsis, persuasion, settled conviction) that we have through Christ toward God — Paul's self-confidence is mediated through Christ (dia Christou pros ton theon). This preposition chain maps the apostolic mediation: confidence flows to God through the Son.",
    "5": "Not that we are sufficient (hikanoi, adequate, qualified) in ourselves to claim anything as coming from us, but our sufficiency is from God — this is the answer to the rhetorical question of 2:16. Hikanotēs (sufficiency, competence) was a term for the professional qualification of a tradesman or official.",
    "6": "Who has made us sufficient to be ministers (diakonous) of a new covenant — diakonos (servant, minister) appears throughout 2 Corinthians as Paul's preferred self-designation (3:6; 4:1; 6:4; 11:15, 23). The new covenant (kainē diathēkē) explicitly echoes Jeremiah 31:31-34 and the Last Supper tradition (1 Cor 11:25). Not of the letter (gramma) but of the Spirit.",
    "8": "Will not the ministry of the Spirit have even more glory? — the qal v'homer (how much more) argument was a standard rabbinic hermeneutical move: if the lesser is true, how much more the greater. Paul applies it to the comparison of the Mosaic and new covenant ministries.",
    "9": "For if there was glory in the ministry of condemnation (katakriseos) — the Mosaic ministry (the law that exposes and condemns sin) had real glory; Paul does not dismiss the Torah. But the ministry of righteousness (dikaiosynes) must far exceed it in glory — the comparative structure honors the old while asserting the new's surpassing quality.",
    "10": "Indeed, in this case, what once had glory has come to have no glory at all, because of the glory that surpasses it — the eclipse metaphor: a candle has real light, but in direct sunlight its light becomes invisible by comparison. The Torah's glory is real but relative.",
    "11": "For if what was being brought to an end came with glory, much more will what is permanent (menon) have glory — the contrast between the fading (katargoumenon) and the permanent (menon) echoes throughout the letter. The temporary/permanent distinction reflects apocalyptic thought about the two ages.",
    "12": "Since we have such a hope, we are very bold (parrēsia, boldness, frank speech) — parrēsia was the Athenian democratic ideal of free speech, the right of every citizen to speak openly before the assembly. Paul adopts the term for the apostolic freedom of speaking the gospel without the concealment that the old covenant ministry required.",
    "13": "Not like Moses, who would put a veil over his face so that the Israelites might not gaze at the outcome of what was being brought to an end — the Exodus 34:29-35 passage describes Moses covering his face with a masveh (veil) after encounters with God. Paul's reading adds the element of concealment of the fading nature of the Mosaic glory.",
    "14": "But their minds were hardened (epōrōthē, were made hard/callous) — the hardening language echoes Isaiah 6:9-10 (make the heart of this people dull) and its NT applications (Matt 13:14-15; John 12:40; Acts 28:26-27). For to this day, when they read the old covenant, that same veil remains unlifted.",
    "15": "Yes, to this day whenever Moses is read a veil lies over their hearts — the synagogue reading of Moses (the Torah) was a regular sabbath practice. Paul describes the veil as lying over the heart (kardian) rather than the face — the location of understanding and will.",
    "16": "But when one turns to the Lord, the veil is removed — the turning (epistrephō) toward the Lord removes the veil; the same verb is used for conversion in the NT (Acts 3:19; 9:35; 26:18). The Exodus text says Moses removed the veil when he entered the presence of the Lord (Exod 34:34).",
    "17": "Now the Lord is the Spirit, and where the Spirit of the Lord is, there is freedom (eleutheria) — the identification of the Lord (kyrios) with the Spirit generates one of the most discussed christological statements in Paul. The freedom (eleutheria) contrasts with the veil of concealment and the bondage of the old covenant.",
    "18": "And we all, with unveiled face, beholding the glory of the Lord, are being transformed (metamorphoumetha) into the same image from one degree of glory to another — the transformation by beholding reflects Hellenistic ideas about assimilation to what one contemplates (Plato, Republic 490a-b: the philosopher becomes like the divine through contemplation). Paul applies this to the Christian's ongoing transformation through the Spirit.",
  },
  "4": {
    "1": "Therefore, having this ministry by the mercy of God, we do not lose heart (ouk enkakounen) — enkakeō (to grow weary, lose heart, become cowardly) was used in military contexts for desertion under pressure. Paul's apostolic persistence reflects the mercy (eleos) that constitutes the ministry, not personal heroism.",
    "2": "But we have renounced disgraceful, underhanded ways — the vocabulary of concealment (kryptō, to hide) and cunning (panourgia, craftiness) that Paul rejects here mirrors the accusations made against him by the super-apostles (11:3; 12:16). Paul's response: we commend ourselves to everyone's conscience before God.",
    "3": "And even if our gospel is veiled, it is veiled to those who are perishing — the veil language from chapter 3 continues; those who cannot see the gospel are not victims of God's arbitrary choice but those who are perishing (apollymenoi) by their own rejection.",
    "4": "In their case the god of this age (ho theos tou aiōnos toutou) has blinded the minds of the unbelievers — the title god of this age for Satan reflects Jewish apocalyptic categories (1 Enoch 54:5; Testament of Job 23:1-2) where the present evil age is under the influence of hostile spiritual powers. The term ho archōn tou kosmou (ruler of this world) appears in John 12:31; 14:30; 16:11.",
    "5": "For what we proclaim is not ourselves, but Jesus Christ as Lord, with ourselves as your servants (douloi) for Jesus's sake — the contrast between self-proclamation (heautous kēryssomen) and Christ-proclamation defines the apostolic task. The servant/doulos language inverts the Roman imperial patron-client hierarchy.",
    "6": "For God, who said let light shine out of darkness, has shone in our hearts — the creation account (Gen 1:3: let there be light) provides the analogy for the new creation event of conversion. The new creation is as real and as powerful as the original creation; both are acts of divine speech into darkness.",
    "7": "But we have this treasure in jars of clay (en ostrakinois skeuesin), to show that the surpassing power belongs to God and not to us — ostrakinos (made of clay/pottery) was used for the cheapest, most common storage vessels. The ostraka (pottery shards) were also used in Athens for voting in the ostracism (exile) procedure, giving us the English word ostracize.",
    "8": "We are afflicted in every way, but not crushed; perplexed, but not driven to despair — the four antitheses in vv.8-9 follow a regular pattern: thlibomenoi (pressed) but not stenochorumenoi (cramped); aporoumenoi (at a loss) but not exaporoumenoi (utterly at a loss). The second term in each pair intensifies the first: Paul nearly reaches the extreme but does not cross it.",
    "9": "Persecuted, but not forsaken; struck down, but not destroyed — the language of violent assault that stops just short of the lethal. The divine protection that prevents the fatal blow is the point: apostolic suffering reaches its limit at the boundary God establishes.",
    "10": "Always carrying in the body the dying of Jesus (tēn nekrōsin tou Iesou) — nekrōsis (dying, mortification) is Paul's term for the death-process of crucifixion that continues in apostolic suffering. The phrase in the body emphasizes the physical reality of this participation in Christ's dying.",
    "11": "For we who live are always being given over to death for Jesus's sake, so that the life of Jesus also may be manifested in our mortal flesh — the double manifestation: death manifested through suffering; life manifested through resurrection power. The mortal flesh (thnētē sarx) is the specific location of divine life's display.",
    "12": "So death is at work in us, but life in you — the pastoral economy of apostolic suffering: Paul's death-in-the-body generates life in the congregation. This is not mystical speculation but pastoral observation of what actually happened at Corinth.",
    "13": "Since we have the same spirit of faith according to what has been written, I believed, and so I spoke — Paul cites Psalm 116:10 (LXX: I believed, therefore I spoke). Psalm 116 is a thanksgiving psalm for deliverance from death; Paul reads it as the apostle's own experience of believing-through-suffering.",
    "14": "Knowing that he who raised the Lord Jesus will raise us also with Jesus and bring us with you into his presence — the resurrection as the practical basis of apostolic endurance. The we/you (Paul and the Corinthians) brought together before God describes the eschatological gathering of the congregation in the presence of Christ.",
    "15": "For it is all for your sake, so that as grace extends to more and more people it may increase thanksgiving, to the glory of God — the missionary expansion of grace (charis) generates an expanding multiplication of thanksgiving (eucharistia); Paul frames apostolic mission as the increase of divine worship.",
    "16": "So we do not lose heart. Though our outer self is wasting away, our inner self is being renewed day by day — the outer/inner distinction (ho exō hēmōn anthrōpos/ho esō hēmōn) reflects the Hellenistic philosophical distinction between the body and the soul/mind. Paul accepts the distinction but transforms it: the inner renewal is through the Spirit, not through philosophical discipline.",
    "17": "For this light momentary affliction is preparing for us an eternal weight of glory beyond all comparison — the Greek wordplay between the lightness (elaphron) of present affliction and the weight (baros) of glory inverts physical intuition. The eternal weight of glory (aiōnion baros doxēs) is an oxymoron in Greek: heavy eternity vs. light temporality.",
    "18": "As we look not to the things that are seen but to the things that are unseen — the visible/invisible distinction maps onto the temporal/eternal distinction. The unseen is the permanent; the seen is the transient. Hebrews 11:1-3 develops the same insight: faith perceives the invisible reality that underlies the visible world.",
  },
  "5": {
    "1": "For we know that if the tent (skēnos) that is our earthly home is destroyed, we have a building from God, a house not made with hands (oikodomēn ek theou), eternal in the heavens — the tent as body metaphor was used in Greek philosophy (Plato, Phaedo 81c: the soul is dragged back into the visible by the body as a tent peg). Paul transforms the image: the tent is not an evil prison but a temporary dwelling whose replacement is not dissolution but transformation.",
    "2": "For in this tent we groan, longing to put on our heavenly dwelling (to oikētērion hēmōn to ex ouranou ependysasthai) — the clothing metaphor for the resurrection body (1 Cor 15:53-54) reappears. Ependysasthai (to put on over, to clothe oneself additionally) implies transformation rather than replacement: the new body is put on over the old, not in place of it.",
    "3": "If indeed by putting it on we may not be found naked — the nakedness of a disembodied state was feared in Greek thought and Jewish apocalyptic. Paul's point is that the resurrection body prevents the nakedness of mere soul-without-body existence.",
    "4": "For while we are still in this tent, we groan, being burdened — not that we would be unclothed, but that we would be further clothed, so that what is mortal may be swallowed up by life — the Epicurean and Platonic traditions both envisioned death as a release from bodily burden; Paul's vision is the opposite: not escape from the body but the transformation of mortality into immortality.",
    "5": "He who has prepared us for this very thing is God, who has given us the Spirit as a guarantee (arrabōn) — the arrabōn (down-payment, earnest money) reappears from 1:22. The commercial metaphor was familiar from Hellenistic papyri; the Spirit is God's advance payment guaranteeing the full transformation to come.",
    "6": "So we are always of good courage (tharrountes) — tharreō (to be courageous, take heart) is Paul's word throughout chapters 5 and 7 for the apostolic confidence grounded in resurrection hope. We know that while we are at home (endemountes) in the body we are away from home (ekdemountes) from the Lord.",
    "7": "For we walk by faith, not by sight (dia pisteos peripatoumen, ou dia eidous) — the contrast between pistis (faith) and eidos (sight, appearance) reflects the epistemological framework Paul has been developing since 4:18 (visible/invisible). Walking dia pisteos rather than dia eidous is the apostolic mode of navigation through the world.",
    "8": "Yes, we are of good courage, and we would rather be away from the body and at home with the Lord — the preference for being with the Lord rather than in the body mirrors Philippians 1:21-23 (to live is Christ, to die is gain; I desire to depart and be with Christ). Both passages reflect a genuinely positive assessment of death for the believer, though resurrection remains the final goal.",
    "9": "So whether we are at home or away, we make it our aim to please him — the ambition (philotimoumetha, to love honor, to be ambitious) Paul redirects from self-advancement to pleasing God. The word philotimia in Roman culture described the honor-seeking of the elite; Paul converts it into service-orientation.",
    "11": "Therefore, knowing the fear of the Lord, we persuade others — the fear of God (phobos tou kyriou) as the motivation for persuasion (peithomen) reflects the prophetic tradition where awareness of divine judgment drives the proclamation. The same awareness of standing before God governs 4:2 and 2:17.",
    "12": "We are not commending ourselves to you again but giving you cause to boast about us — the letter is not another self-defense (apologeomai) but provision for the Corinthians' own boasting (kauchēma) on Paul's behalf. Those who boast in outward appearance (en prosōpō) rather than the heart reflect the super-apostles' appeal to visible credentials.",
    "13": "For if we are beside ourselves (exestēmen, we have been out of our minds), it is for God; if we are in our right mind (sōphronoumen), it is for you — the alleged madness of Paul's ecstatic experiences (mystical visions, speaking in tongues) serves God; his sober self-presentation serves the congregation. The tension mirrors 1 Cor 14:18-19: Paul speaks in tongues more than all but prefers five intelligible words in the assembly.",
    "14": "For the love of Christ controls us (synechei hēmas, holds us together, constrains us) — synechō (to press together, hold in place) was used for armies hemming in an enemy and for the grip of disease. The love of Christ is Paul's controlling force; it presses him into service rather than allowing drift.",
    "15": "And he died for all, that those who live might no longer live for themselves but for him who for their sake died and was raised — the died-for-all (hyper pantōn) and the living-no-longer-for-self maps the atonement's ethical consequence. The purpose clause (hina — so that) makes the death consequential: the cross creates a new mode of living.",
    "16": "From now on, therefore, we regard no one according to the flesh (kata sarka) — the eschatological dividing line (from now on, apo tou nyn) marks the new-creation epistemology: the old categories of human evaluation no longer apply. Even though we once regarded Christ according to the flesh, we regard him thus no longer — Paul's pre-conversion understanding of Jesus as a failed messianic pretender has been overturned by the resurrection.",
    "17": "Therefore, if anyone is in Christ, he is a new creation (kainē ktisis) — the phrase kainē ktisis (new creation) appears in Galatians 6:15 as the thing that counts beyond circumcision or uncircumcision. Jewish apocalyptic awaited a new creation (1 Enoch 45:4-5; 72:1; Isaiah 65:17); Paul announces that it has begun in Christ.",
    "18": "All this is from God, who through Christ reconciled us to himself and gave us the ministry of reconciliation (diakonian tēs katallagēs) — katallagē (reconciliation, exchange, restoration of relationship) appears for the first time in the NT in Romans 5:10-11 and here. The word was used for the ending of hostility between parties and the restoration of commercial or diplomatic relations.",
    "19": "That is, in Christ God was reconciling the world (kosmon) to himself, not counting their trespasses against them — the cosmic scope (kosmos) of reconciliation echoes Colossians 1:20 (reconciling all things). The not-counting of trespasses (mē logizomenos, not reckoning) reflects the accounting metaphor: the debt has been cancelled.",
    "20": "Therefore, we are ambassadors for Christ (hyper Christou oun presbeuo), God making his appeal through us — presbeuo was the technical term for serving as a diplomatic envoy of a king or emperor. The ambassador speaks with the authority of the one who sent him; Paul's proclamation carries the authority of the divine King whose message he carries.",
    "21": "For our sake he made him to be sin (hamartian epoiēsen) who knew no sin, so that in him we might become the righteousness of God — the great exchange: Christ takes what is ours (sin) so that we receive what is his (righteousness). The phrase made him to be sin reflects both the sin-offering (hatta't) of Leviticus 4-5 where the sacrifice becomes identified with sin, and the scapegoat of Leviticus 16 that bears the community's sins away.",
  }
}

